   243		err := xml.Unmarshal(body, &xmlMap)
   244		if err != nil {
   245			return 0, err
   246		}
   247	
   248		path, err := kedautil.GetValueByPath(xmlMap, valueLocation)
   249		if err != nil {
   250			return 0, err
   251		}
   252	
   253		switch v := path.(type) {
   254		case int:
   255			return float64(v), nil
   256		case int64:
   257			return float64(v), nil
   258		case float64:
   259			return v, nil
   260		case string:
   261			r, err := resource.ParseQuantity(v)
   262			if err != nil {
   263				return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
   264			}
   265			return r.AsApproximateFloat64(), nil
   266		default:
   267			return 0, fmt.Errorf(valueLocationWrongErrorMsg, v)
   268		}
   269	}
